   319→    /**
   320→     * @param  camelContext   the camel context from which the {@link BacklogDebugger} should be found.
   321→     * @param  createIfAbsent indicates whether a {@link BacklogDebugger} should be created if it cannot be found
   322→     * @return                the instance of {@link BacklogDebugger} that could be found in the context or that was
   323→     *                        created if {@code createIfAbsent} is set to {@code true}, {@code null} otherwise.
   324→     */
   325→    private static BacklogDebugger getBacklogDebugger(CamelContext camelContext, boolean createIfAbsent) {
   326→        BacklogDebugger debugger = null;
   327→        if (camelContext.getRegistry() != null) {
   328→            // lookup in registry
   329→            Map<String, BacklogDebugger> map = camelContext.getRegistry().findByTypeWithName(BacklogDebugger.class);
   330→            if (map.size() == 1) {
   331→                debugger = map.values().iterator().next();
   332→            }
   333→        }
   334→        if (debugger == null) {
   335→            debugger = camelContext.hasService(BacklogDebugger.class);
   336→        }
   337→        if (debugger == null && createIfAbsent) {
   338→            // fallback to use the default backlog debugger
   339→            debugger = DefaultBacklogDebugger.createDebugger(camelContext);
   340→        }
   341→        return debugger;
   342→    }
   343→
   344→    private void backlogDebuggerSetupInitialBreakpoints(
   345→            NamedNode definition, NamedRoute routeDefinition, boolean first,
   346→            BacklogDebugger debugger, NamedNode targetOutputDef) {
   347→        // setup initial breakpoints
   348→        if (debugger.getInitialBreakpoints() != null) {
   349→            boolean match = false;
   350→            String id = definition.getId();
   351→            for (String pattern : debugger.getInitialBreakpoints().split(",")) {
   352→                pattern = pattern.trim();
   353→                match |= BacklogDebugger.BREAKPOINT_ALL_ROUTES.equals(pattern) && first;
   354→                if (!match) {
   355→                    match = PatternHelper.matchPattern(id, pattern);
   356→                }
   357→                // eip kind so you can match with (setBody*)
   358→                if (!match) {
   359→                    match = PatternHelper.matchPattern(definition.getShortName(), pattern);
   360→                }
   361→                // location and line number
   362→                if (!match && pattern.contains(":")) {
   363→                    // try with line number and location
   364→                    String pnum = StringHelper.afterLast(pattern, ":");
   365→                    if (pnum != null) {
   366→                        String ploc = StringHelper.beforeLast(pattern, ":");
   367→                        String loc = definition.getLocation();
   368→                        // strip schema
   369→                        if (loc != null && loc.contains(":")) {
   370→                            loc = StringHelper.after(loc, ":");
   371→                        }
   372→                        String num = String.valueOf(definition.getLineNumber());
   373→                        if (PatternHelper.matchPattern(loc, ploc) && pnum.equals(num)) {
   374→                            match = true;
   375→                        }
   376→                    }
   377→                }
   378→                // line number only
   379→                if (!match) {
   380→                    Integer pnum = camelContext.getTypeConverter().tryConvertTo(Integer.class, pattern);
   381→                    if (pnum != null) {
   382→                        int num = definition.getLineNumber();
   383→                        if (num == pnum) {
   384→                            match = true;
   385→                        }
   386→                    }
   387→                }
   388→            }
   389→            if (match) {
   390→                if (first && debugger.isSingleStepIncludeStartEnd()) {
   391→                    // we want route to be breakpoint (use input)
   392→                    id = routeDefinition.getInput().getId();
   393→                    debugger.addBreakpoint(id);
   394→                    LOG.debug("BacklogDebugger added breakpoint: {}", id);
   395→                } else {
   396→                    // first output should also be breakpoint
   397→                    id = targetOutputDef.getId();
   398→                    debugger.addBreakpoint(id);
   399→                    LOG.debug("BacklogDebugger added breakpoint: {}", id);
   400→                }
   401→            }
   402→        }
   403→    }
