   357→            // input/output types on routes
   358→            camelContext.setUseDataType(true);
   359→        }
   360→
   361→        // wrap with variable
   362→        if (variable != null) {
   363→            internal.addAdvice(new VariableAdvice(variable));
   364→        }
   365→
   366→        // and create the route that wraps all of this
   367→        route.setProcessor(internal);
   368→        route.getProperties().putAll(routeProperties);
   369→        route.setStartupOrder(startupOrder);
   370→        if (isAutoStartup != null) {
   371→            LOG.debug("Using AutoStartup {} on route: {}", isAutoStartup, definition.getId());
   372→            route.setAutoStartup(isAutoStartup);
   373→        }
   374→
   375→        // after the route is created then set the route on the policy processor(s) so we get hold of it
   376→        internal.setRouteOnAdvices(route);
   377→
   378→        // invoke init on route policy
   379→        if (routePolicyList != null && !routePolicyList.isEmpty()) {
   380→            for (RoutePolicy policy : routePolicyList) {
   381→                policy.onInit(route);
   382→            }
   383→        }
   384→
   385→        // inject the route error handler for processors that are error handler aware
   386→        // this needs to be done here at the end because the route may be transactional and have a transaction error handler
