   362→    public boolean willCreateNewThreadPool(ExecutorServiceAwareDefinition<?> definition, boolean useDefault) {
   363→        ExecutorServiceManager manager = camelContext.getExecutorServiceManager();
   364→        ObjectHelper.notNull(manager, "ExecutorServiceManager", camelContext);
   365→
   366→        if (definition.getExecutorServiceBean() != null) {
   367→            // no there is a custom thread pool configured
   368→            return false;
   369→        } else if (definition.getExecutorServiceRef() != null) {
   370→            ExecutorService answer = lookupByNameAndType(definition.getExecutorServiceRef(), ExecutorService.class);
   371→            // if no existing thread pool, then we will have to create a new
   372→            // thread pool
   373→            return answer == null;
